'use strict';

// Loaded ONLY inside the forked worker, lazily on the first call -- models the
// transform toolchain a Metro worker loads per task (babel.config.js, the preset +
// plugin graph), which no other process in the tree ever sees. Its attestation can
// come from nothing but the worker's own shard.
module.exports = { transform: (input, hello) => `worked on ${input} with ${hello}` };
